package com.interview.incidentrca.security;
import jakarta.servlet.*;import jakarta.servlet.http.*;import lombok.RequiredArgsConstructor;import org.springframework.security.authentication.*;import org.springframework.security.core.context.SecurityContextHolder;import org.springframework.security.core.userdetails.UserDetailsService;import org.springframework.stereotype.Component;import org.springframework.web.filter.OncePerRequestFilter;import java.io.IOException;
@Component @RequiredArgsConstructor public class JwtAuthenticationFilter extends OncePerRequestFilter{private final JwtService jwt;private final UserDetailsService details;
 protected void doFilterInternal(HttpServletRequest req,HttpServletResponse res,FilterChain chain)throws ServletException,IOException{String h=req.getHeader("Authorization"); if(h!=null&&h.startsWith("Bearer ")){try{String email=jwt.subject(h.substring(7));var user=details.loadUserByUsername(email);SecurityContextHolder.getContext().setAuthentication(new UsernamePasswordAuthenticationToken(user,null,user.getAuthorities()));}catch(Exception ignored){}} chain.doFilter(req,res);} }
